import React, { useCallback, useMemo, useState } from "react";
import { ScrollView, Pressable, TextInput } from "react-native";
import { VStack, Box, Text } from '../../../';
import type { IListBoxSelect } from "@lmb/kitsconcerto-types";
import { useSelectBase } from "../hooks/useSelectBase";
import KitsContainer from "../../Helpers/FormContainer";
import { resolveThemeTokenForNative } from "@lmb/kitsconcertomobile";

const KitsListBox = (props: IListBoxSelect) => {
    const {
        id,
        label,
        disabled,
        invalid,
        errors,
        helperText,
        inputSize = "md",
        isMultiple,
        withFilter,
        filterBy,
        hideError,
    } = props;

    const { list, labelKey, valueKey, childrenKey, onChange, selectedValue } = useSelectBase();

    const [filterText, setFilterText] = useState("");

    const t = resolveThemeTokenForNative;
    const primaryBg = t('primary.100') || '#E8EAF6';
    const primaryText = t('primary.700') || '#303F9F';
    const borderClr = invalid ? (t('red.500') || '#EF4444') : (t('gray.300') || '#D1D5DB');
    const textColor = t('gray.800') || '#1F2937';
    const placeholderColor = t('gray.400') || '#9CA3AF';
    const groupBg = t('gray.50') || '#F9FAFB';

    const isSelected = useCallback((val: any) => {
        if (isMultiple && Array.isArray(selectedValue)) {
            return selectedValue.includes(val);
        }
        return selectedValue === val;
    }, [isMultiple, selectedValue]);

    const onSelect = useCallback((val: any, item: any) => {
        if (isMultiple && Array.isArray(selectedValue)) {
            const newVals = selectedValue.includes(val)
                ? selectedValue.filter((v: any) => v !== val)
                : [...selectedValue, val];
            onChange({ target: { value: newVals } }, newVals);
        } else {
            onChange({ target: { value: val } }, item);
        }
    }, [isMultiple, selectedValue, onChange]);

    const filteredList = useMemo(() => {
        if (!withFilter || !filterText.trim()) return list;
        const query = filterText.toLowerCase();
        const searchKey = filterBy || labelKey;

        if (childrenKey) {
            return list.reduce((acc: any[], group: any) => {
                const children = group[childrenKey];
                if (Array.isArray(children)) {
                    const matched = children.filter((item: any) =>
                        String(item[searchKey] ?? "").toLowerCase().includes(query)
                    );
                    if (matched.length > 0) {
                        acc.push({ ...group, [childrenKey]: matched });
                    }
                }
                return acc;
            }, []);
        }

        return list.filter((item: any) =>
            String(item[searchKey] ?? "").toLowerCase().includes(query)
        );
    }, [list, filterText, withFilter, filterBy, labelKey, childrenKey]);

    const renderItem = (item: any, index: number) => {
        const val = item[valueKey];
        const selected = isSelected(val);
        return (
            <Pressable
                key={`${val}-${index}`}
                style={{
                    padding: 10,
                    backgroundColor: selected ? primaryBg : 'transparent',
                }}
                onPress={() => !disabled && onSelect(val, item)}
            >
                <Text
                    color={selected ? primaryText : textColor}
                    fontWeight={selected ? "bold" : "normal"}
                    size={inputSize}
                >
                    {item[labelKey]}
                </Text>
            </Pressable>
        );
    };

    const renderGroupedItems = () => {
        return filteredList.map((group: any, gi: number) => {
            const children = group[childrenKey!];
            if (!Array.isArray(children)) {
                return renderItem(group, gi);
            }
            return (
                <Box key={`group-${gi}`}>
                    <Box style={{ backgroundColor: groupBg, paddingHorizontal: 12, paddingVertical: 8 }}>
                        <Text fontWeight="600" color={textColor} size={inputSize}>
                            {group[labelKey]}
                        </Text>
                    </Box>
                    {children.map((item: any, ci: number) => renderItem(item, ci))}
                </Box>
            );
        });
    };

    return (
        <KitsContainer
            id={id}
            label={label}
            invalid={!!invalid}
            hideError={hideError}
            helperText={helperText}
            errors={errors}
        >
            <Box
                borderWidth={1}
                borderColor={borderClr}
                borderRadius="$sm"
                height={250}
                opacity={disabled ? 0.5 : 1}
            >
                {withFilter && (
                    <TextInput
                        value={filterText}
                        onChangeText={setFilterText}
                        placeholder="Search..."
                        placeholderTextColor={placeholderColor}
                        style={{
                            borderBottomWidth: 1,
                            borderBottomColor: borderClr,
                            paddingHorizontal: 12,
                            paddingVertical: 8,
                            fontSize: 14,
                            color: textColor,
                        }}
                    />
                )}
                <ScrollView>
                    <VStack>
                        {childrenKey
                            ? renderGroupedItems()
                            : filteredList.map((item: any, i: number) => renderItem(item, i))
                        }
                    </VStack>
                </ScrollView>
            </Box>
        </KitsContainer>
    );
};

export default KitsListBox;
